extension CompareFunction: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeCompareFunction: FfiConverterRustBuffer {
    typealias SwiftType = CompareFunction

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> CompareFunction {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .never
        
        case 2: return .less
        
        case 3: return .equal
        
        case 4: return .lessEqual
        
        case 5: return .greater
        
        case 6: return .notEqual
        
        case 7: return .greaterEqual
        
        case 8: return .always
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: CompareFunction, into buf: inout [UInt8]) {
        switch value {
        
        
        case .never:
            writeInt(&buf, Int32(1))
        
        
        case .less:
            writeInt(&buf, Int32(2))
        
        
        case .equal:
            writeInt(&buf, Int32(3))
        
        
        case .lessEqual:
            writeInt(&buf, Int32(4))
        
        
        case .greater:
            writeInt(&buf, Int32(5))
        
        
        case .notEqual:
            writeInt(&buf, Int32(6))
        
        
        case .greaterEqual:
            writeInt(&buf, Int32(7))
        
        
        case .always:
            writeInt(&buf, Int32(8))
        
        }
    }
}


